```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");

  // Begin transaction
  auto transaction_result = conn_result.and_then(sqlgen::begin_transaction);

  // Delete users with last_login before 2025-01-01
  auto delete_result = transaction_result.and_then(
    [](auto&& trans) {
      return (sqlgen::delete_from<User> | 
              sqlgen::where(User::last_login < "2025-01-01"))(trans);
    }
  );

  // Commit the transaction and return the result
  return delete_result.and_then([](auto&& trans) {
    return trans->commit();
  }).transform([](auto&&) { return 0; })
    .or_else([](auto&& error) { return -1; });
}

} // namespace delete_inactive_users
```

