```cpp
#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  struct Student {
    sqlgen::PrimaryKey<std::string> SNo;
    std::string SName;
    int Sex = 1;
    std::optional<std::string> Birthday;
    std::optional<int> Major;
    float Scorses = 0.0f;
    std::optional<std::string> Remark;
  };

  struct Course {
    sqlgen::PrimaryKey<int> CID;
    std::string CName;
    int Term = 1;
    std::optional<int> CTime;
    float Credit = 0.0f;
  };

  struct Score {
    std::string SNo;
    int CID;
    std::optional<float> Score;

    // Composite primary key
    sqlgen::PrimaryKey<decltype(SNo), decltype(CID)> PrimaryKey;

    // Foreign key constraints
    sqlgen::ForeignKey<Student, &Student::SNo> SNo_FK;
    sqlgen::ForeignKey<Course, &Course::CID> CID_FK;
  };

  void design_eas_database() {
    // Connect to SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Drop tables if they exist
    (sqlgen::drop<Student> | sqlgen::if_exists)(conn);
    (sqlgen::drop<Course> | sqlgen::if_exists)(conn);
    (sqlgen::drop<Score> | sqlgen::if_exists)(conn);

    // Create tables
    sqlgen::create_table<Student>(conn);
    sqlgen::create_table<Course>(conn);
    sqlgen::create_table<Score>(conn);
  }

}
```

## Key Implementation Details:

1. **Struct Definitions**: Each table is defined as a struct with appropriate field types and sqlgen attributes:
   - `sqlgen::PrimaryKey` for primary key fields
   - `std::optional` for nullable fields
   - Default values are set using assignment in the struct definition
   - Foreign key relationships are defined using `sqlgen::ForeignKey`

2. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

3. **Table Management**:
   - Uses `sqlgen::drop<T> | sqlgen::if_exists` pattern to safely drop tables if they exist
   - Uses `sqlgen::create_table<T>` to create the tables with proper schema

4. **Type Mapping**:
   - `varchar(10)` → `std::string` (length handled by sqlgen)
   - `datetime` → `std::optional<std::string>` (using string representation)
   - `int`/`float` → standard C++ types
   - `auto_increment PK` → handled by `sqlgen::PrimaryKey<int>` for Course table

The implementation follows sqlgen best practices and leverages the library's type-safe database operations as demonstrated in the reference materials.

